import asyncio
import json
import math
import os
import time
import uuid
from typing import Dict, Any, List, Optional, Set

import websockets
from websockets.server import WebSocketServerProtocol


HOST = os.getenv("GAME_HOST", "0.0.0.0")
PORT = int(os.getenv("GAME_PORT", "8765"))
TICK_RATE = float(os.getenv("TICK_RATE", "20"))
WORLD_BOUNDS = {
    "min_x": 0.0,
    "min_y": 0.0,
    "max_x": 10000.0,
    "max_y": 10000.0,
}
MAX_NAME_LEN = 32
MOVE_SPEED_LIMIT = 800.0
PING_INTERVAL = 10.0
PLAYER_TIMEOUT = 30.0


def now() -> float:
    return time.time()


def clamp(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except Exception:
        return default


def sanitize_name(name: Any) -> str:
    if not isinstance(name, str):
        return "Player"
    name = name.strip()
    if not name:
        return "Player"
    return name[:MAX_NAME_LEN]


class Player:
    __slots__ = (
        "id",
        "name",
        "ws",
        "x",
        "y",
        "rotation",
        "hp",
        "alive",
        "velocity_x",
        "velocity_y",
        "last_input_at",
        "last_seen_at",
        "joined_at",
    )

    def __init__(self, player_id: str, ws: WebSocketServerProtocol, name: str):
        self.id = player_id
        self.name = sanitize_name(name)
        self.ws = ws
        self.x = 0.0
        self.y = 0.0
        self.rotation = 0.0
        self.hp = 100
        self.alive = True
        self.velocity_x = 0.0
        self.velocity_y = 0.0
        self.last_input_at = now()
        self.last_seen_at = now()
        self.joined_at = now()

    def to_public_state(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "x": self.x,
            "y": self.y,
            "rotation": self.rotation,
            "hp": self.hp,
            "alive": self.alive,
            "velocity_x": self.velocity_x,
            "velocity_y": self.velocity_y,
        }


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[WebSocketServerProtocol, str] = {}
        self.lock = asyncio.Lock()
        self.running = True

    async def register(self, ws: WebSocketServerProtocol, name: str) -> Player:
        async with self.lock:
            player_id = str(uuid.uuid4())
            player = Player(player_id, ws, name)
            spawn_x = safe_float(os.getenv("SPAWN_X", "5000"))
            spawn_y = safe_float(os.getenv("SPAWN_Y", "5000"))
            player.x = clamp(spawn_x, WORLD_BOUNDS["min_x"], WORLD_BOUNDS["max_x"])
            player.y = clamp(spawn_y, WORLD_BOUNDS["min_y"], WORLD_BOUNDS["max_y"])
            self.players[player_id] = player
            self.connections[ws] = player_id
            return player

    async def unregister(self, ws: WebSocketServerProtocol) -> None:
        async with self.lock:
            player_id = self.connections.pop(ws, None)
            if player_id:
                self.players.pop(player_id, None)

    async def handle_message(self, ws: WebSocketServerProtocol, raw: str) -> None:
        try:
            msg = json.loads(raw)
        except Exception:
            await self.send_error(ws, "invalid_json")
            return

        if not isinstance(msg, dict):
            await self.send_error(ws, "invalid_message")
            return

        msg_type = msg.get("type")
        player = await self.get_player_by_ws(ws)
        if not player:
            await self.send_error(ws, "not_registered")
            return

        player.last_seen_at = now()

        if msg_type == "input":
            await self.handle_input(player, msg)
        elif msg_type == "ping":
            await self.send_json(ws, {"type": "pong", "ts": now()})
        elif msg_type == "set_name":
            player.name = sanitize_name(msg.get("name"))
        else:
            await self.send_error(ws, "unknown_type")

    async def handle_input(self, player: Player, msg: Dict[str, Any]) -> None:
        x = clamp(safe_float(msg.get("x"), player.x), WORLD_BOUNDS["min_x"], WORLD_BOUNDS["max_x"])
        y = clamp(safe_float(msg.get("y"), player.y), WORLD_BOUNDS["min_y"], WORLD_BOUNDS["max_y"])
        rotation = safe_float(msg.get("rotation"), player.rotation)
        vx = safe_float(msg.get("velocity_x"), 0.0)
        vy = safe_float(msg.get("velocity_y"), 0.0)

        speed = math.hypot(vx, vy)
        if speed > MOVE_SPEED_LIMIT:
            scale = MOVE_SPEED_LIMIT / speed
            vx *= scale
            vy *= scale

        player.x = x
        player.y = y
        player.rotation = rotation
        player.velocity_x = vx
        player.velocity_y = vy
        player.last_input_at = now()

    async def get_player_by_ws(self, ws: WebSocketServerProtocol) -> Optional[Player]:
        async with self.lock:
            player_id = self.connections.get(ws)
            if not player_id:
                return None
            return self.players.get(player_id)

    async def send_error(self, ws: WebSocketServerProtocol, error: str) -> None:
        await self.send_json(ws, {"type": "error", "error": error})

    async def send_json(self, ws: WebSocketServerProtocol, payload: Dict[str, Any]) -> None:
        try:
            await ws.send(json.dumps(payload, separators=(",", ":")))
        except Exception:
            pass

    async def broadcast_state_loop(self) -> None:
        tick_interval = 1.0 / TICK_RATE
        while self.running:
            started = now()
            await self.broadcast_full_state()
            elapsed = now() - started
            await asyncio.sleep(max(0.0, tick_interval - elapsed))

    async def broadcast_full_state(self) -> None:
        async with self.lock:
            players = list(self.players.values())
            if not players:
                return

            state = {
                "type": "state",
                "server_time": now(),
                "world": WORLD_BOUNDS,
                "players": [p.to_public_state() for p in players],
            }

            payload = json.dumps(state, separators=(",", ":"))
            targets = [p.ws for p in players]

        await asyncio.gather(*(self.safe_send_raw(ws, payload) for ws in targets), return_exceptions=True)

    async def safe_send_raw(self, ws: WebSocketServerProtocol, payload: str) -> None:
        try:
            await ws.send(payload)
        except Exception:
            await self.unregister(ws)

    async def housekeeping_loop(self) -> None:
        while self.running:
            cutoff = now() - PLAYER_TIMEOUT
            stale: List[WebSocketServerProtocol] = []
            async with self.lock:
                for player in self.players.values():
                    if player.last_seen_at < cutoff:
                        stale.append(player.ws)

            for ws in stale:
                try:
                    await ws.close()
                except Exception:
                    pass
                await self.unregister(ws)

            await asyncio.sleep(1.0)

    async def ping_loop(self) -> None:
        while self.running:
            async with self.lock:
                sockets = [p.ws for p in self.players.values()]
            for ws in sockets:
                try:
                    await ws.ping()
                except Exception:
                    await self.unregister(ws)
            await asyncio.sleep(PING_INTERVAL)

    async def handler(self, ws: WebSocketServerProtocol) -> None:
        player: Optional[Player] = None
        try:
            first = await asyncio.wait_for(ws.recv(), timeout=5.0)
            try:
                hello = json.loads(first)
            except Exception:
                await self.send_error(ws, "expected_join")
                return

            if not isinstance(hello, dict) or hello.get("type") != "join":
                await self.send_error(ws, "expected_join")
                return

            player = await self.register(ws, hello.get("name", "Player"))
            await self.send_json(
                ws,
                {
                    "type": "welcome",
                    "id": player.id,
                    "tick_rate": TICK_RATE,
                    "world": WORLD_BOUNDS,
                },
            )

            async for raw in ws:
                if isinstance(raw, bytes):
                    continue
                await self.handle_message(ws, raw)
        except Exception:
            pass
        finally:
            await self.unregister(ws)

    async def run(self) -> None:
        async with websockets.serve(
            self.handler,
            HOST,
            PORT,
            ping_interval=None,
            max_size=2**20,
            compression=None,
        ):
            await asyncio.gather(
                self.broadcast_state_loop(),
                self.housekeeping_loop(),
                self.ping_loop(),
            )


